set-variable.value:
@{
            var name = (string)context.Request.MatchedParameters["deploymentName"];
            var doc  = Newtonsoft.Json.Linq.JObject.Parse((string)context.Variables["deployments-json"]);
            var match = ((Newtonsoft.Json.Linq.JArray)doc["value"])
                .FirstOrDefault(d => (string)d["name"] == name);
            return match != null ? match.ToString(Newtonsoft.Json.Formatting.None) : string.Empty;
        }

return-response.set-body:
@{
                var match = (string)context.Variables["matched-deployment"];
                if (!string.IsNullOrEmpty(match)) { return match; }
                var name = (string)context.Request.MatchedParameters["deploymentName"];
                return "{\"error\": \"deployment not found: " + name + "\"}";
            }
